Code:
public int[] withoutTen(int[] nums) {
    int pointer = 0;
    for (int i = 0; i < nums.length; i++) {
        if (nums[i] != 10) {
            nums[pointer++] = nums[i];
        }
    }

    while (pointer < nums.length) {
        nums[pointer++] = 0;
    }

    return nums;
}

